   }

   for (const auto &I : FS.getCallsiteSamples()) {
@@ -160,7 +169,7 @@ void SampleProfileMatcher::findProfileAnchors(const FunctionSamples &FS,
     if (isInvalidLineOffset(Loc.LineOffset))
       continue;
     for (const auto &C : I.second)
